    /**
     * Derive document boundaries from an already-produced ExtractionResult(crate.types.ExtractionResult).
     *
     * Builds a MultidocInput from {@code result.pages} (one PageSignals per
     * {@code PageContent} entry), then delegates to detect_boundaries.
     *
     * # Fallback behaviour
     *
     * - If {@code result.pages} is {@code None} or empty the whole document is treated as a
     *   single document: returns {@code [Start(1), End(1)]}, matching the contract of
     *   detect_boundaries for a one-page input.
     *
     * # Text density
     *
     * {@code PageContent} does not carry a pre-computed density score.
     * This function approximates density as
     * {@code non_whitespace_chars / total_chars} (clamped to {@code [0.0, 1.0]}), which is a
     * reasonable proxy for how text-dense a page is relative to itself.  Pass a
     * custom MultidocInput to detect_boundaries directly when you need a
     * higher-fidelity density measurement (e.g. chars-per-pt² from a PDF extractor).
     * {@literal @}param result — Extraction result whose {@code pages} field will be used.
     *
     * {@literal @}param thresholds — Detection thresholds forwarded to detect_boundaries.
     */
    public static List<DocumentBoundary> boundariesFromExtractionResult(
        final ExtractionResult result,
        final MultidocThresholds thresholds
    ) throws KreuzbergRsException {
        java.util.Objects.requireNonNull(result, "result must not be null");
        java.util.Objects.requireNonNull(thresholds, "thresholds must not be null");
        return KreuzbergRs.boundariesFromExtractionResult(result, thresholds);
    }

    /**
     * Detect document boundaries in a multi-document PDF.
     *
     * Returns a list of detected boundaries, always including implicit boundaries
     * at start (page 1) and end (page_count).  Boundaries are returned in ascending
     * order of {@code start_page}.
     * {@literal @}param input Page signals for the PDF
     *
     * {@literal @}param thresholds Detection thresholds
     *
     * {@literal @}return Ordered list of document boundaries.
     */
    public static List<DocumentBoundary> detectBoundaries(
        final MultidocInput input,
        final MultidocThresholds thresholds
    ) throws KreuzbergRsException {
        java.util.Objects.requireNonNull(input, "input must not be null");
        java.util.Objects.requireNonNull(thresholds, "thresholds must not be null");
        return KreuzbergRs.detectBoundaries(input, thresholds);
    }

    /**
     * Decide which call mode best fits this document.
     *
     * Rules applied in order:
     *
     * 1. {@code image/*} → StructuredCallMode.VisionOnly (no text layer to start from).
     * 2. {@code application/pdf} → StructuredCallMode.TextOnly regardless of
     *    {@code text_coverage} or embedded image count.  Kreuzberg's OCR + text-layer
     *    extraction produces text for scanned PDFs; the orchestrator's
     *    post-call confidence gate handles any vision escalation actually needed.
     * 3. DOCX / {@code text/html} / {@code text/*} / {@code application/json} / {@code application/xml} /
     *    {@code application/rtf} with {@code avg_chars_per_page &gt; docx_text_min_density}
     *    → StructuredCallMode.TextOnly.
     * 4. Anything else → StructuredCallMode.Skip.
     *
     * After rule selection two post-rule promotions apply (in order):
     *
     * - {@code user_force_vision} promotes {@code TextOnly} → {@code TextPlusVision}
     *   ({@code Skip} stays {@code Skip} — caller meant to opt out).
     * - {@code enable_vision_fallback} promotes {@code TextOnly} →
     *   {@code TextOnlyWithVisionFallback} (does **not** upgrade {@code TextPlusVision} or
     *   {@code Skip}).
     */
    public static StructuredCallMode chooseCallMode(final StructuredInput input, final StructuredThresholds t) throws KreuzbergRsException {
        java.util.Objects.requireNonNull(input, "input must not be null");
        java.util.Objects.requireNonNull(t, "t must not be null");
        return KreuzbergRs.chooseCallMode(input, t);
    }

